import React from 'react';

const UserCard = ({ onClick }) => {
  return (
    <div 
      className="bg-gray-800 rounded-lg p-4 flex items-center gap-3 cursor-pointer hover:bg-gray-700 transition-colors"
      onClick={onClick}
    >
      <div className="relative">
        <img 
          src="https://images.unsplash.com/photo-1494790108755-2616b612b786?w=40&h=40&fit=crop&crop=face" 
          alt="Profile" 
          className="w-10 h-10 rounded-full object-cover"
        />
        <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-gray-800"></div>
      </div>
      <div className="flex-1">
        <h3 className="text-white font-medium">Alena Siphron</h3>
        <p className="text-gray-400 text-sm">UI/UX Designer</p>
      </div>
      <div className="text-xs bg-green-500 text-white px-2 py-1 rounded">
        Available
      </div>
    </div>
  );
};

export default UserCard;
